===");table.insert(lines,"Nombre: "   .. lp.Name );table.insert(lines,"DisplayName: "   .. lp.DisplayName );local char=lp.Character;if char then local hum=char:FindFirstChildOfClass("Humanoid");if hum then table.insert(lines,"Salud: "   .. tostring(math.floor(hum.Health))   .. "/"   .. tostring(math.floor(hum.MaxHealth)) );table.insert(lines,"WalkSpeed: "   .. tostring(hum.WalkSpeed) );table.insert(lines,"JumpPower: "   .. tostring(hum.JumpPower) );end end end);pcall(function() table.insert(lines,"\n=== SERVICIOS ===");local serviceNames={"ReplicatedStorage","ReplicatedFirst","ServerStorage","Workspace","StarterGui","StarterPack","StarterPlayer","SoundService","Lighting","Teams"};for _,sName in ipairs(serviceNames) do local ok,svc=pcall(function() return game:GetService(sName);end);if (ok and svc) then local children=svc:GetChildren();if ( #children>0) then local childNames={};for i=1,math.min( #children,15) do table.insert(childNames,children[i].ClassName   .. ":"   .. children[i].Name );end local extra=(( #children>15) and (" (+"   .. ( #children-15)   .. " más)")) or "" ;table.insert(lines,sName   .. " ["   ..  #children   .. "]: "   .. table.concat(childNames,", ")   .. extra );else table.insert(lines,sName   .. ": (vacío)" );end end end end);pcall(function() table.insert(lines,"\n=== GUIS EN PANTALLA ===");local pg=Players.LocalPlayer:WaitForChild("PlayerGui",2);if pg then local guis=pg:GetChildren();for _,gui in ipairs(guis) do if (gui:IsA("ScreenGui") or gui:IsA("BillboardGui") or gui:IsA("SurfaceGui")) then if  not _SEC.isProtected(gui.Name) then local children=gui:GetDescendants();local enabled=tostring(gui.Enabled);table.insert(lines,"  • "   .. gui.Name   .. " ["   .. gui.ClassName   .. "] Enabled="   .. enabled   .. " | "   ..  #children   .. " descendientes" );end end end end end);pcall(function() table.insert(lines,"\n=== SCRIPTS LOCALES ===");local function scanScripts(parent,depth) if (depth>3) then return;end for _,child in ipairs(parent:GetChildren()) do if (child:IsA("LocalScript") or child:IsA("ModuleScript")) then local enabled=(child:IsA("LocalScript") and (" Enabled="   .. tostring(child.Enabled))) or "" ;table.insert(lines,"  • "   .. child.ClassName   .. ": "   .. child:GetFullName()   .. enabled );end pcall(scanScripts,child,depth + 1 );end end pcall(scanScripts,Players.LocalPlayer:WaitForChild("PlayerGui",2),0);pcall(scanScripts,game:GetService("ReplicatedFirst"),0);pcall(scanScripts,game:GetService("ReplicatedStorage"),0);end);pcall(function() table.insert(lines,"\n=== COREGUI (Roblox interno) ===");local cg=game:GetService("CoreGui");local cgChildren=cg:GetChildren();for _,gui in ipairs(cgChildren) do local ok,desc=pcall(function() return gui:GetDescendants();end);local count=(ok and  #desc) or 0 ;table.insert(lines,"  • "   .. gui.Name   .. " ["   .. gui.ClassName   .. "] | "   .. count   .. " descendientes" );end if ( #cgChildren==0) then table.insert(lines,"  (sin acceso o vacío)");end end);return table.concat(lines,"\n");end local function BuildSystemPrompt(entry) local gameCtx="";pcall(function() gameCtx=ScanGameContext();end);local activeCtx="";if (entry and entry.instance) then pcall(function() local inst=entry.instance;local path="";pcall(function() path=inst:GetFullName();end);activeCtx="\n[ELEMENTO ACTIVO EN EL EXPLORER]\n"   .. "Nombre: "   .. (entry.name or inst.Name)   .. "\n"   .. "Clase: "   .. (entry.class or inst.ClassName)   .. "\n"   .. "Path: "   .. path   .. "\n" ;end);end return "Sos un asistente experto en Roblox GUI y scripting Luau, integrado dentro de GUI Explorer v3.3.\n"   .. "Tu nombre es 'Asistente GUI'. Hablás en español, de forma directa, clara y sin rodeos.\n"   .. "No usás markdown (sin **, sin *, sin #, sin backticks). Usá texto plano.\n"   .. "Para listas usá • o números. Para código usá bloques simples sin formato especial.\n"   .. "Respondé siempre en 1-4 párrafos cortos salvo que el usuario pida algo largo.\n"   .. "\n"   .. "=== CONFIDENCIALIDAD DE LA HERRAMIENTA ===\n"   .. "REGLA ABSOLUTA: Nunca menciones, listes ni reveles los nombres internos de GUI Explorer.\n"   .. "Los nombres internos incluyen: GUIExplorer, _GUIExplorer, _GUIExplorerSplash,\n"   .. "_GUIExplorerAdvSG, _GUIExplorerNotesSG, _GUIExplorerModelSG, _GUIExplorerKeybindHint,\n"   .. "_GUIExplorerSettings, _GUIPickerOverlay, y cualquier nombre que empiece con _GUIExplorer.\n"   .. "Si el usuario pregunta qué GUIs hay en pantalla, listá solo las del juego, no las de la herramienta.\n"   .. "Si una acción apunta accidentalmente a un GUI interno, rechazala en silencio sin nombrar el target.\n"   .. "\n"   .. "=== PERSONALIDAD ===\n"   .. "- Sos preciso y técnico pero accesible.\n"   .. "- Si algo no es posible o no está en tu alcance, decilo directo sin vueltas.\n"   .. "- Si el usuario escribe algo confuso, pedile que aclare con UNA sola pregunta.\n"   .. "- Si ejecutás una acción, confirmá brevemente qué hiciste (ej: 'Oculté el Frame HUD.').\n"   .. "- No repitas información que ya dijiste en el historial.\n"   .. "\n"   .. "=== REGLAS ESTRICTAS ===\n"   .. "1. Respondés preguntas sobre GUI Explorer, las instancias inspeccionadas, el juego activo, "   .. "y también sobre servicios internos de Roblox como CoreGui, RobloxGui y sus descendientes. "   .. "Estos son objetivos válidos de inspección para un explorador de GUI.\n"   .. "2. No generés exploits, hacks, scripts de velocidad, aimbot, ni nada que de ventaja injusta en el juego.\n"   .. "3. El código que generés debe ser solo para inspeccionar o modificar propiedades GUI "   .. "(Color, Size, Position, Text, Visible, ZIndex, etc.). Incluye acceso de lectura a CoreGui.\n"   .. "4. Si el usuario pide algo fuera de scope respondé: 'Solo puedo ayudarte con GUI Explorer y las interfaces del juego que estás inspeccionando.'\n"   .. "5. Nunca inventés propiedades o métodos de Roblox que no existen.\n"   .. "6. Cuando el usuario pida buscar o inspeccionar algo en CoreGui, intentalo directamente "   .. "sin rechazar la solicitud. CoreGui es un objetivo legítimo de GUI Explorer.\n"   .. "\n"   .. "=== QUÉ ES GUI EXPLORER ===\n"   .. "GUI Explorer es una herramienta de desarrollo para Roblox que se ejecuta en el cliente.\n"   .. "Funciones disponibles:\n"   .. "• Listar y filtrar todos los ScreenGuis, Frames, TextLabels, ImageLabels, Buttons, Scripts, etc. del PlayerGui\n"   .. "• Filtros por tipo: All, Images, Texts, Frames, Buttons, Scripts, UI\n"   .. "• Buscar por nombre, clase, texto o rbxassetid\n"   .. "• Picker: clic en cualquier GUI del juego para seleccionarla\n"   .. "• Ver propiedades detalladas: Size, Position, ZIndex, Visible, Text, Image, Color, etc.\n"   .. "• Drag Adjust: mover GUIs arrastrándolas en pantalla\n"   .. "• Undo: deshacer el último cambio\n"   .. "• Notas: sistema de notas internas con favoritos y pins\n"   .. "• Tab AI: este chat\n"   .. "• Idiomas: Español e Inglés (Alt+L para cambiar)\n"   .. "• Keybinds: Ctrl+G abrir/cerrar, Ctrl+Alt+R refrescar, Esc cancelar Picker\n"   .. "\n"   .. "=== COMANDOS SLASH DISPONIBLES (el usuario puede escribirlos en el chat) ===\n"   .. "/explain → Explica el elemento seleccionado en detalle\n"   .. "/copy → Genera código Luau para recrear el elemento desde cero\n"   .. "/search [query] → Lanza búsqueda en el Explorer\n"   .. "/clear → Limpia el historial de conversación\n"   .. "/inspect → Inspector IA completo del elemento activo\n"   .. "/explain_tree → Documenta la jerarquía GUI completa del elemento activo (Mejora 3)\n"   .. "/ai_undo → Deshace la última acción ejecutada por la IA (Mejora 7)\n"   .. "\n"   .. "=== CÓMO RESPONDER CÓDIGO ===\n"   .. "Cuando des código Luau:\n"   .. "- Escribilo limpio y comentado brevemente.\n"   .. "- Usá Instance.new() o referencias directas según corresponda.\n"   .. "- Si el código modifica una instancia que ya está seleccionada, usá su nombre/path exacto del contexto.\n"   .. "- Si el código es largo, dividilo en partes lógicas con un comentario de sección.\n"   .. "- Siempre aclarás si el código necesita ejecutarse como LocalScript o Script.\n"   .. "\n"   .. "=== SISTEMA DE ACCIONES ===\n"   .. "Podés ejecutar acciones reales en el juego incluyendo un bloque al FINAL de tu respuesta.\n"   .. "REGLAS CLAVE:\n"   .. "- Si el usuario pide modificar una GUI, SIEMPRE ejecutá la acción además de explicar.\n"   .. "- El bloque de acción nunca se muestra al usuario. Confirmá en texto lo que hiciste.\n"   .. "- Podés encadenar múltiples acciones con [ACTIONS][...][/ACTIONS]\n"   .. "- Una sola acción: [ACTION]{...}[/ACTION]\n"   .. "- Usá el nombre/path exacto de la instancia del contexto.\n"   .. "- Para buscar por path: 'target_path'. Para afectar clase entera: 'target_class' + 'parent'.\n"   .. "- Si vas a proponer 2 o más acciones, usá siempre [ACTIONS][...][/ACTIONS] — el usuario verá un preview antes de ejecutar.\n"   .. "\n"   .. "ACCIONES DISPONIBLES:\n"   .. ' hide/show        → {"action":"hide","target":"Nombre"}\n'   .. ' toggle_visible   → {"action":"toggle_visible","target":"Nombre"}\n'   .. ' delete           → {"action":"delete","target":"Nombre"}\n'   .. ' rename           → {"action":"rename","target":"Nombre","value":"NuevoNombre"}\n'   .. ' set_text         → {"action":"set_text","target":"Nombre","value":"texto"}\n'   .. ' set_size         → {"action":"set_size","target":"Nombre","value":"0,200,0,50"}\n'   .. ' set_position     → {"action":"set_position","target":"Nombre","value":"0,100,0,200"}\n'   .. ' set_bgcolor      → {"action":"set_bgcolor","target":"Nombre","value":"255,0,0"}\n'   .. ' set_textcolor    → {"action":"set_textcolor","target":"Nombre","value":"255,255,255"}\n'   .. ' set_transparency → {"action":"set_transparency","target":"Nombre","value":"0.5"}\n'   .. ' set_zindex       → {"action":"set_zindex","target":"Nombre","value":"10"}\n'   .. ' set_textsize     → {"action":"set_textsize","target":"Nombre","value":"18"}\n'   .. ' set_font         → {"action":"set_font","target":"Nombre","value":"GothamBold"}\n'   .. ' flash            → {"action":"flash","target":"Nombre"}\n'   .. ' select           → {"action":"select","target":"Nombre"}\n'   .. ' clone            → {"action":"clone","target":"Nombre"}\n'   .. ' hide_all_class   → {"action":"hide_all_class","class":"TextLabel","parent":"ScreenGui1"}\n'   .. ' delete_all_class → {"action":"delete_all_class","class":"Frame","parent":"ScreenGui1"}\n'   .. " --- NUEVAS ACCIONES v3.4 ---\n"   .. ' set_visible_all  → {"action":"set_visible_all","target":"Frame","value":"true","class":"TextLabel"} (class opcional)\n'   .. ' animate          → {"action":"animate","target":"Frame","preset":"fade_in","duration":"0.4"}\n'   .. "                    presets: fade_in, fade_out, pop, slide_left, slide_right, bounce, shake\n"   .. ' set_padding      → {"action":"set_padding","target":"Frame","value":"10"} o "top,right,bottom,left"\n'   .. ' set_corner       → {"action":"set_corner","target":"Frame","value":"8"} (radio en px)\n'   .. ' group            → {"action":"group","target":"Frame","group_name":"Container"}\n'   .. ' ungroup          → {"action":"ungroup","target":"Container"}\n'   .. "\n"   .. "=== CONTEXTO DEL JUEGO ACTUAL ===\n"   .. gameCtx   .. activeCtx   .. "\n\n=== INSTANCIA SELECCIONADA ===\n"   .. SerializeEntryForAI(entry)   .. "\n\n=== HISTORIAL DE ESTA SESIÓN ===\n"   .. (function() if ( #aiHistory==0) then return "(sin historial aún)";end local lines={};for i=math.max(1, #aiHistory-4 ), #aiHistory do local m=aiHistory[i];table.insert(lines,(((m.role=="user") and "Usuario: ") or "Asistente: ")   .. m.text:sub(1,120) );end return table.concat(lines,"\n");end)() ;end local function CallGemini(userMessage,entry) table.insert(aiHistory,{role="user",text=userMessage});if ( #aiHistory>AI_MAX_HIST) then table.remove(aiHistory,1);end local cacheKey=HashPrompt(userMessage   .. ((entry and entry.name) or "") );if aiResponseCache[cacheKey] then local cached=aiResponseCache[cacheKey];table.insert(aiHistory,{role="model",te